declare @AccountName nvarchar(1024)
set @AccountName = ''
select @AccountName = case when @@language = 'E' then ' - ' + rtrim(ten_tk2) else ' - ' + rtrim(ten_tk) end from dmtk where tk = @tk
if @AccountName = ' - ' set @AccountName = ''
select @tk + @AccountName as tk, @ngay_bc as ngay_bc, @so_ngay as so_ngay
exec rs_rptDueSalesInvoiceReport @ngay_bc, @tk, @so_ngay, @ma_kh, @nh_kh1, @nh_kh2, @nh_kh3, @ma_dvcs, @nhom, @@language, @@userID, @@admin
&DynamicFieldFilterPara;
        &ReferenceParameters;






      &OutlineEntry;
      &JavascriptReportFilter;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
   if (!f.getItemValue('ngay_bc')) f.setItemValue('ngay_bc', new Date());
  f.live(f.getItem('ngay_bc'));
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, d = f.getItem('ngay_bc').value, s = f.getItem('tk').value, n = f.getItemValue('so_ngay'), type = (f.getItemValue('nhom') == '0');
      g._alterTitle = [null, [['%s', s, true], ['%d', d, true], ['%n', n, true]]];
      g._hiddenFields = [
        {Fields: 'ma_nt, t_tt_nt0, da_tt_nt, cl_nt', Value: (f.getItemValue('mau_bc') == '10')},
        {Fields: 'ma_hd, ten_hd_ex', Value: type)}
      ];
      g._hiddenForms = [
        {Form: [2, 3, 8, 7], Value: type},
        {Form: [0, 1, 6, 5], Value: !type}
      ];
      remove$GridReport$Filter(g);
      break;
    default:
      break;
  }
}
/* </flatten> */



